**اختبار الموقع**
```python
import requests
import webbrowser

# إضافة مواقع ويب التي تريد اختبارها
مواقع_ويب = {
    "example.com": "https://www.example.com",
    "google.com": "https://www.google.com",
    "facebook.com": "https://www.facebook.com"
}

# استدعاء الدالة التي تاختبار الموقع
def اختبار_الموقع(الموقع):
    try:
        # إرسال طلب GET إلى الموقع
        response = requests.get(الموقع)
        # إذا كان الموقع متاحًا، افتح الموقع في المتصفح
        if response.status_code == 200:
            webbrowser.open(الموقع)
            print(f"الموقع {الموقع} متاح.")
        else:
            print(f"الموقع {الموقع} غير متاح.")
    except requests.exceptions.RequestException as e:
        print(f"حدث خطأ في اختبار الموقع {الموقع}: {e}")

# اختبار مواقع ويب
for موقع in مواقع_ويب:
    اختبار_الموقع(مواقع_ويب[موقع])
```

